module clockPulser(clk, rst, maxValue, clk_out);
	input clk, rst;
	input [31:0] maxValue;
	output reg clk_out=0;
	reg [31:0] counter = 1;
	always @(posedge clk) begin
		if (rst) begin
			counter <= 1;
			clk_out <= 1'b0;
		end
		else begin
			counter <= counter + 1'b1;
			if (counter == maxValue) begin
				clk_out <= 1;
				counter <= 1;
			end
			else
				clk_out <= 0;
		end
	end
endmodule

