module ALU(
	input [15:0] Operand1,
	input [15:0] Operand2,
	input [2:0] Alu_Opcode,
	input Shift,
   output [15:0] Result,
	output Zero_Out
	);
reg IsZero;
reg [15:0] Temp;
assign Zero_Out = IsZero;
assign Result = Temp;
   always @(*) begin
      case(Alu_Opcode)
			// Add
         3'b000:begin
				Temp = Operand1 + Operand2;
				IsZero = (Temp == 0);				
			end
			// AddI
         3'b001:begin
				Temp = Operand1 + Operand2;
				IsZero = (Temp == 0);
			end
			// Shift Left(<<) And Right(>>)
         3'b010:begin
				if (Shift == 1)begin
					Temp = Operand1 >> Operand2;
					IsZero = (Temp == 0);
				end
				else begin
					Temp = Operand1 << Operand2; 
					IsZero = (Temp == 0);
				end
			end
			 // Rotate Left And Rotate Right 
			3'b011: begin
				if (Shift == 1)begin
					Temp = (Operand1 >> Operand2) | (Operand1 << (16 - Operand2));
					IsZero = (Temp == 0);
				end
				else begin
					Temp = (Operand1 << Operand2) | (Operand1 >> (16 - Operand2));
					IsZero = (Temp == 0);
				end
			end
			//Beqz
			3'b100: begin
			  Temp = Operand1 - Operand2;
			  IsZero = (Temp == 0);
			end
			// Store Word
			3'b101: begin
				Temp = Operand2;
				IsZero = (Temp == 0);
			end
			// Load Word
			3'b110: begin
				Temp = Operand2;
				IsZero = (Temp == 0);
			end
			//Jump
		   3'b111: begin
				Temp = Operand1 + Operand2;
				IsZero = (Temp == 0);
		   end
      endcase
   end
endmodule

module Immediate_Unit
(   
	input [6:0] op_i,
	input [31:0]  Instruction_bus_i,
   output reg [31:0] Immediate_o
);
always@(op_i or Instruction_bus_i) begin
	// Se indica la estructura del bus de instrucciones dependiendo del tipo de instrucci贸n
	if(op_i == 7'h13 || op_i == 7'h03 || op_i == 7'h67)
		Immediate_o = {{20{Instruction_bus_i[31]}},Instruction_bus_i[31:20]};// I format
	else if(op_i == 7'h37 || op_i == 7'h17)
		Immediate_o = {{12{Instruction_bus_i[31]}},Instruction_bus_i[31:12]};// U format
	else if(op_i == 7'h23)
		Immediate_o = {{21{Instruction_bus_i[31]}},Instruction_bus_i[30:25],Instruction_bus_i[11:7]}; //S format
	else if(op_i == 7'h63)
		Immediate_o = {{20{Instruction_bus_i[31]}},Instruction_bus_i[7],Instruction_bus_i[30:25],Instruction_bus_i[11:8], 1'b0}; //B format
	else if(op_i == 7'h6F)
		Immediate_o = {{11{Instruction_bus_i[31]}},Instruction_bus_i[31],Instruction_bus_i[19:12],Instruction_bus_i[20],Instruction_bus_i[30:21],1'b0}; // J format
	else
		Immediate_o = 0;// R format
end
endmodule // signExtend

module halfadder2 (sum, carry, a, b);
  input a, b;
  output sum, carry;
  reg sum, carry;
  always @ (a or b)
  begin
    if (a == 0 && b == 0)
      begin
        sum = 0; carry = 0;
      end
    else if (a == 0 && b == 1)
      begin
      sum = 1; carry = 0;
      end
    else if (a == 1 && b == 0)
      begin
      sum = 1; carry = 0;
      end
    else
      begin
        sum = 0; carry = 1;
      end
    end
endmodule

