module alu(a, b, ALUControl, Result, ALUFlags);
    input [31:0] a, b;
    input [2:0] ALUControl;
    // ALUControl  | Operaci贸n
    // 000         | ADD
    // 001         | SUB
    // 010         | AND
    // 011         | ORR
    // 100         | EOR
    output [31:0] Result;
    output [3:0] ALUFlags;
    wire N, Z, C, V;
    wire [32:0] sum;
    wire [31:0]_b;
    assign _b = (ALUControl[0]? ~b : b); // Sin _b, el resultado es diferente.
    assign sum = a + _b + ALUControl[0];
    // Us茅 esto en lugar del switch para que Result no sea un reg.
    assign Result = ALUControl[2]? a^b:
        ALUControl[1]? (ALUControl[0]? (a|b) : (a&b)) : sum;
    assign N = Result[31];
    assign Z = Result == 0;
    and(C, sum[32], ~ALUControl[1]);
    and(V, ~ALUControl[1], sum[31] ^ a[31], ~ALUControl[0] ^ a[31] ^ b[31]);
    assign ALUFlags = {N, Z, C, V};
endmodule

module drv_bus_resp(
	input clk_sys,
	input ready,
	input ok,
	input en,
	input pe,
	input [0:15] a3,
	input req,
	output reg dok,
	output reg den,
	output reg dpe,
	output reg [0:15] ddt
);
	// response trigger: any response for an active request
	wire resp = req & ready & (ok | en);
	localparam IDLE = 4'd0;
	localparam RESP = 4'd1;
	reg [0:0] state = IDLE;
	always @ (posedge clk_sys) begin
		case (state)
			IDLE: begin
				if (resp) begin
					dok <= ok;
					den <= en;
					dpe <= pe;
					ddt <= a3;
					state <= RESP;
				end
			end
			RESP: begin
				if (!req) begin
					dok <= 0;
					den <= 0;
					dpe <= 0;
					ddt <= 16'd0;
					state <= IDLE;
				end
			end
		endcase
	end
endmodule
