module modulo_checker(
functional_output,
clk,
rst_n,
out,
done
);
localparam 	MODULO = 419;
parameter	DATA_WIDTH = 16;
input  		[DATA_WIDTH-1:0]	functional_output;
input 							clk;
input							rst_n;
output		[15:0]	out;
output		reg		done;
//output 		[15:0] 	out;
function integer log2(input integer value);
		begin
			value = value - 1;
			for (log2 = 0; value > 0; log2 = log2 + 1) begin
				value = value >> 1;
			end
		end
endfunction
localparam	OUT_WIDTH		= log2(MODULO);
reg 	[DATA_WIDTH-1:0] 		decremental_output;
reg								new_ip;
reg		[OUT_WIDTH-1:0]			dout;
//reg		[15:0]		dout;
assign out = done ? dout : 0;
always @ (posedge clk) begin
if (!rst_n) begin
		decremental_output <= 0;
		dout <= 0;
		new_ip <= 1;
		done <= 0;
end
else begin
		new_ip <= 0;
	if (decremental_output > 0) begin
		decremental_output <= decremental_output - 1;
		done <= 0;
		if (dout < MODULO-1)
			dout <= dout + 1;
		else
			dout <= 0;
	end
	else begin
		decremental_output <= new_ip ? functional_output : decremental_output;
		dout <= new_ip ? 0 : dout;
		done <= new_ip ? 0 : 1;
	end
end  // else block
end // always block
endmodule

module Sign_Extend(
    data_i,	
    data_o	  
);
// Ports
input 	[31:0] 		data_i;
output 	[31:0] 		data_o;
reg 	[31:0] 		data_o;
always @ (data_i) begin
		case(data_i[6:0])
		// R-Type (Arithmetic)
		7'b0110011: begin
			data_o[31:0]  = 32'b0;
		end
		// I-Type (Immediate Arithmetic) 
		7'b0010011: begin
			data_o[31:0] = {{20{data_i[31]}},data_i[31:20]};
		end
		// I-Type (Load) 
		7'b0000011: begin
			data_o[31:0] = {{20{data_i[31]}},data_i[31:20]};
		end
		// S-Type (Store)
		7'b0100011: begin
			data_o[31:12] = {20{data_i[31]}};
			data_o[11:5] = data_i[31:25];
			data_o[4:0] = data_i[11:7];
		end
		// SB-Type (Branch)
		7'b1100011: begin
			data_o[31:11] = {21{data_i[31]}};
			data_o[10] = data_i[7];
			data_o[9:4] = data_i[30:25];
			data_o[3:0] = data_i[11:8];
		end
		7'b0000000: begin
			data_o[31:0] = 32'b0;
		end
	endcase	
end
endmodule

