reg [7:0]	keycode_o;
reg	[7:0]	revcnt;
always @( posedge ps2_clk_in or negedge keyboard_off)
	begin
		if (!keyboard_off)
			revcnt=0;
		else if (revcnt >=10) 
			revcnt=0;
		else
			revcnt=revcnt+1;
	end
always @(posedge ps2_clk_in) 
begin
	case (revcnt[3:0])
