module ALU #(parameter WL = 32, sel=4)
(input [WL-1:0] ALUIn1,ALUIn2,
input [4:0] shamt,//shift amount     
input [sel-1:0] ALUsel,
output reg signed [WL-1:0] ALUOut, 
output reg Zero); 
reg [WL-1:0] Result;
always @(*) begin
Zero <= 1'b0;
    case (ALUsel)
    4'b0000: 
        Result <= ALUIn1 & ALUIn2; 
    4'b0001:
        Result <= ALUIn1 | ALUIn2;
    4'b0010:
        Result <= ALUIn1+ALUIn2;
    4'b0011:
        Result <= ALUIn2<<shamt; 
    4'b0100:
        Result <= ALUIn2>>shamt; 
    4'b0101:
        Result <= ALUIn2>>>shamt; 
    4'b0110: begin
        Result <= ALUIn1 - ALUIn2;
        if(Result == 0)
         Zero = 1'b1;
        end
    4'b0111: begin
        if(ALUIn1<ALUIn2)begin
           Result = 1;
           end
           else begin
           Result = 0;
           end
        end
    4'b1000:
        Result <= ALUIn2<<ALUIn1;
    4'b1001:
        Result <= ALUIn2>>ALUIn1;
    4'b1010:
        Result <= (ALUIn2>>>ALUIn1); 
    4'b1011: 
        Result <= ALUIn1*ALUIn2;
    default: 
        Result <= 32'h00000000;
    endcase
     ALUOut = Result;
    end 
endmodule

