    );
    localparam  [CTRBITS-1:0]
        ADD     =   4'b0000     ,
        AND     =   4'b0001     ,
        NOR     =   4'b0010     ,
        OR      =   4'b0011     ,
        SLL     =   4'b0100     ,
        SRL     =   4'b0101     ,
        SRA     =   4'b0110     ,
        SUB     =   4'b0111     ,
        XOR     =   4'b1000     ,
        SRAV    =   4'b1001     ,
        SRLV    =   4'b1010     ,
        SLLV    =   4'b1011     ,
        SLT     =   4'b1100     ,
        LUI     =   4'b1101     ;
    always @(*)
	begin :    control
		case(ALU_op)
		  `ALURtp     :
		      begin   :   RType
		          case(i_funct)
		              `Add    :   ALU_control =   ADD ;
		              `Addu   :   ALU_control =   ADD ;
		              `And    :   ALU_control =   AND ;
		              `Jarl   :   ALU_control =   ADD ;
