		              `Srl    :   ALU_control =   SRL ;
		              `Srlv   :   ALU_control =   SRLV;
		              `Sub    :   ALU_control =   SUB ;
		              `Subu   :   ALU_control =   SUB ;
		              `Xor    :   ALU_control =   XOR ;
		              default :   ALU_control =   ADD ;
		          endcase
		      end
          `ALUAdd       :   ALU_control =   ADD     ;
