module pfpu_f2i(
	input sys_clk,
	input alu_rst,
	input [31:0] a,
	input valid_i,
	output reg [31:0] r,
	output reg valid_o
);
wire		a_sign = a[31];
wire [7:0]	a_expn = a[30:23];
wire [23:0]	a_mant = {1'b1, a[22:0]};
reg [30:0] shifted;
always @(*) begin
	if(a_expn >= 8'd150)
		shifted = a_mant << (a_expn - 8'd150);
	else
		shifted = a_mant >> (8'd150 - a_expn);
end
always @(posedge sys_clk) begin
	if(alu_rst)
		valid_o <= 1'b0;
	else
		valid_o <= valid_i;
	if(a_sign)
		r <= 32'd0 - {1'b0, shifted};
	else
		r <= {1'b0, shifted};
end
endmodule

module    ic_req_upload(//input
                         clk,
                         rst,
                         ic_flits_req,
                         v_ic_flits_req,
                         req_fifo_rdy,
                         //output
                         ic_flit_out,
                         v_ic_flit_out,
								 ic_ctrl_out,
                         ic_req_upload_state
                         );
//input
input                         clk;
input                         rst;
input       [47:0]            ic_flits_req;
input                         v_ic_flits_req;
input                         req_fifo_rdy;
//output
output      [15:0]             ic_flit_out;
output                         v_ic_flit_out;
output      [1:0]              ic_ctrl_out;
output                         ic_req_upload_state;
//parameter 
parameter    ic_req_upload_idle=1'b0;
parameter    ic_req_upload_busy=1'b1;
//reg          ic_req_nstate; 
reg          ic_req_state;
reg  [47:0]  ic_req_flits;
reg  [1:0]   sel_cnt;
reg          v_ic_flit_out;
reg          fsm_rst;
reg          next;
reg          en_flits_in;
reg          inc_cnt;
assign ic_req_upload_state=ic_req_state;
always@(*)
begin
  //default value
 // ic_req_nstate=ic_req_state;
  v_ic_flit_out=1'b0;
  inc_cnt=1'b0;
  fsm_rst=1'b0;
  en_flits_in=1'b0;
  next=1'b0;
  case(ic_req_state)
    ic_req_upload_idle:
       begin
         if(v_ic_flits_req)
           begin
             en_flits_in=1'b1;
             next=1'b1;
           end
       end
    ic_req_upload_busy:
       begin
         if(req_fifo_rdy)
           begin
             if(sel_cnt==2'b10)
               fsm_rst=1'b1;
             inc_cnt=1'b1;
             v_ic_flit_out=1'b1;
           end
       end
    endcase
end
// fsm state
always@(posedge clk)
begin
  if(rst||fsm_rst)
    ic_req_state<=1'b0;
else if(next)
    ic_req_state<=1'b1;
end
// flits regs
always@(posedge clk)
begin
  if(rst||fsm_rst)
    ic_req_flits<=48'h0000;
  else if(en_flits_in)
    ic_req_flits<=ic_flits_req;
end
reg  [15:0]  ic_flit_out;
reg  [1:0]   ic_ctrl_out;
always@(*)
begin
  case(sel_cnt)
    2'b00:
	   begin
	     ic_flit_out=ic_req_flits[47:32];
	     ic_ctrl_out=2'b01;
	   end
    2'b01:
	   begin
	     ic_flit_out=ic_req_flits[31:16];
		  ic_ctrl_out=2'b10;
		end
    2'b10:
	   begin
	     ic_flit_out=ic_req_flits[15:0];
		  ic_ctrl_out=2'b11;
		end
    default:
	   begin
	     ic_flit_out=ic_req_flits[47:32];
		  ic_ctrl_out=2'b00;
	   end
  endcase
end
///sel_counter
always@(posedge clk)
begin
  if(rst||fsm_rst)
    sel_cnt<=2'b00;
  else if(inc_cnt)
    sel_cnt<=sel_cnt+2'b01;
end
endmodule

