module Barrel_Shifter #(parameter WIDTH=8)(
    input[WIDTH-1:0] in,fill,   //Input
    input[3:0] sramt,           //Shift/Rotate Amount
    output reg[WIDTH-1:0] out 
    );
    always @(*) begin
