                    4'b1000: if(WIDTH>8) out={in[WIDTH-9:0],fill[WIDTH-1:WIDTH-8]};
                    4'b1000: if(WIDTH>9) out={in[WIDTH-10:0],fill[WIDTH-1:WIDTH-9]};
