                    4'b1101: if(WIDTH>14) out={in[WIDTH-15:0],fill[WIDTH-1:WIDTH-14]};
                    4'b1110: if(WIDTH>15) out={in[WIDTH-16:0],fill[WIDTH-1:WIDTH-15]};
                    4'b1111: if(WIDTH>16) out=fill;
