			reg_write_enable = 0;
			mem_write_enable = 1;
			dst_data_source  = 3; // No Source
			exception        = 0;
		end
		7'b0010011: begin // I-type
			imm              = i_type_imm;
			reg_write_enable = 1;
			mem_write_enable = 0;
			dst_data_source  = 2; // Alu
