module int_calc(clk, operation, opa, opb, out);
input           clk;
input           [2:0] operation; 
input	        [15:0]	opa, opb;
output          [15:0]	out;      
reg         [15:0]  out_temp; 
integer i;
always @ (clk) begin
    case (operation)
    3'b000: out_temp <= opa + opb;           // A + B
    3'b001: out_temp <= opa - opb;           // A - B
    3'b010: out_temp <= opa * opb;           // A x B
    3'b011: out_temp <= opa / opb;           // A / B
    3'b100: out_temp <= opa % opb;           // A % B      
    endcase
end
