endmodule

module car(clk,reset_n,ent_sensor,exit_sensor,pass1,GREEN_LED,RED_LED);
input clk,reset_n,ent_sensor,exit_sensor;
input [1:0] pass1;
output wire GREEN_LED,RED_LED;
parameter idle = 3'b000, wait_pass = 3'b001, wrong_pass = 3'b010, right_pass = 3'b011;
reg[2:0] current_state, next_state;
reg[31:0] counter_wait;
reg red_tmp,green_tmp;
always @(posedge clk or negedge reset_n)
begin
if(~reset_n)
current_state = idle;
else
current_state = next_state;
end
always @(posedge clk or negedge reset_n)
begin
if(~reset_n)
counter_wait <= 0;
else if(current_state==wait_pass)
counter_wait <= counter_wait + 1;
else
counter_wait <= 0; 
end
always @(*)
begin
case(current_state)
idle: begin
if(ent_sensor == 1)
next_state = wait_pass;
else
next_state = idle;
end
wait_pass: begin
if(counter_wait <= 3)
next_state = wait_pass;
else
begin
if(pass1==2'b01)
next_state = right_pass;
else
next_state = wrong_pass;
end
end
right_pass: begin
if(ent_sensor==1 && exit_sensor == 1)
next_state = idle;
else if(exit_sensor== 1)
next_state = idle;
else
next_state = right_pass; 
end
wrong_pass: begin
if(pass1==2'b01)
next_state = right_pass;
else
next_state = wrong_pass;
end
default: next_state = idle;
endcase
end
always @(posedge clk) begin 
 case(current_state)
 idle: begin
 green_tmp = 1'b0;
 red_tmp = 1'b0;
 end
 wait_pass: begin
 green_tmp = 1'b0;
 red_tmp = 1'b1;
 end
 wrong_pass: begin
 green_tmp = 1'b0;
 red_tmp = ~red_tmp;
 end
 right_pass: begin
 green_tmp = ~green_tmp;
 red_tmp = 1'b0;
 end
 endcase
 end
 assign RED_LED = red_tmp  ;
 assign GREEN_LED = green_tmp;
endmodule

module UartTx(clk, nrst, tx_data, tx_start, tx_busy, txd);
//module UartTx(clk, nrst, tx_do_sample, tx_data, tx_start, tx_busy, txd);
parameter CLK_HZ = 200_000_000;
parameter BAUD = 9600;
parameter BAUD_DIVISOR = CLK_HZ / BAUD;
input wire clk;
input wire nrst;
//input wire tx_do_sample;
input wire [7:0] tx_data;
input wire tx_start;		// write strobe
output reg tx_busy = 0;
output reg txd = 1;
reg [9:0] tx_shifter = 0;
reg [15:0] tx_sample_cntr = 0;
always @ (posedge clk) begin
	if ((~nrst) || (tx_sample_cntr[15:0] == 0)) begin
		tx_sample_cntr[15:0] <= (BAUD_DIVISOR-1);
	end else begin
		tx_sample_cntr[15:0] <= tx_sample_cntr[15:0] - 1;
	end
end
wire tx_do_sample = (tx_sample_cntr[15:0] == 0);
always @ (posedge clk) begin
	if (~nrst) begin
		tx_busy <= 0;
		tx_shifter[9:0] <= 0;
		txd <= 1;
	end else begin
		if (~tx_busy) begin
			if (tx_start) begin		// asynchronous data load and 'busy' set
				tx_shifter[9:0] <= {1'b1,tx_data[7:0],1'b0};
				tx_busy <= 1;
			end
		end else begin
			if (tx_do_sample) begin		// next bit
				{tx_shifter[9:0],txd} <= {tx_shifter[9:0],txd} >> 1;	// txd MUST change only on tx_do_sample although data may be loaded earlier
				if (~|tx_shifter[9:1]) begin		// early asynchronous 'busy' reset
					tx_busy <= 0;					// txd still holds data, but shifter is ready to get new info
				end
			end	// tx_do_sample
		end	// ~tx_busy
	end // ~nrst
end
endmodule

