module musicbox(clk, sw1, sw2, sw3, spk1);
input clk, sw1, sw2, sw3;
output reg spk1;
reg [25:0] clk_counter = 0;
reg [25:0] limiter = 25_000_000;
parameter hundred = 3, ten = 8, digit = 6; // the last 3-digits of my student id is 383 -> 386
reg [3:0] num = 10;
always @(*) begin
	// check for pressing switch
	if (sw1 == 0) begin
		// Pressing S7 set num to 3 -- highest priority
		num = hundred;
	end else if (sw2 == 0) begin
		// Pressing S6 set num to 8
		num = ten;
	end else if (sw3 == 0) begin
		// Pressing S5 set num to 6
		num = digit;
	end else begin
		// Not pressing anything set num to 10 (which means no sound)
		num = 10;
	end
	// choose frequency via num
	case(num)
		1: limiter = 25_000_000 / 262; // C4
		2: limiter = 25_000_000 / 294; // D4
		3: limiter = 25_000_000 / 330; // E4
		4: limiter = 25_000_000 / 349; // F4
		5: limiter = 25_000_000 / 392; // G4
		6: limiter = 25_000_000 / 440; // A4
		7: limiter = 25_000_000 / 494; // B4
		8: limiter = 25_000_000 / 524; // C5
		9: limiter = 25_000_000 / 587; // D5
		0: limiter = 25_000_000 / 659; // E5
		default: limiter = 0;		   // No Sound
	endcase
end
// clock divider --> input frequency to buzzer
always @(posedge clk) begin
	clk_counter = clk_counter + 1;
	if (clk_counter >= limiter) begin
		if (limiter > 0) begin
			spk1 = ~spk1;
		end else begin
			spk1 = 0;
		end
		clk_counter = 0;
	end
end
endmodule

`timescale 1ns/1ns
module SSU(busy, mclk, rst, iSCL, oSDA);
    input busy;
    input mclk;
    input rst;
    output reg iSCL;
    output reg oSDA;
reg [2:0] state, next_state;
parameter [2:0] idle=3'b000, startC=3'b001, stopC=3'b010, zero =3'b011, one = 3'b100;
always @(state or busy) begin
    case(state)
        idle: if(busy) next_state = startC;
            else    next_state = idle;
        startC:  if(busy) next_state= one;
            else    next_state = stopC;
        one: if(busy) next_state = one;
            else next_state = stopC;
        stopC:   if(busy) next_state = startC;
            else    next_state = stopC;
    endcase
end
always @(posedge mclk or negedge rst) begin
    if(!rst) begin
        state = idle;
    end
    else begin 
      state = next_state;
    end
end
always @(posedge mclk or negedge rst) begin
    if(!rst) begin
        iSCL = 1'b1;
        oSDA = 1'b0;
    end
    else
        case(next_state)
        idle: begin 
            iSCL = 1'b1;
            oSDA = 1'b0;
            end
        startC:begin 
            iSCL = ~iSCL;
            oSDA = 1'b1;
            end
        one: begin
            iSCL = ~iSCL;
            oSDA = 1'b0;
        end
        stopC:begin
            iSCL =1'b1;
            oSDA = 1'b0;
            end
        endcase
end
endmodule

module Mealy_Zero_Detector (
  output reg y_out, 
  input x_in, clock, reset
);
  reg [1: 0]	state, next_state;
  parameter	S0 = 2'b00, S1 = 2'b01, S2 = 2'b10, S3 = 2'b11;
  always @ (posedge clock, negedge reset)	// state transition
    if (reset == 0) state <= S0;
    else state <= next_state;
  always @ (state, x_in) // Form the next state
    case (state)
      S0:	if (x_in)   next_state = S1; else next_state = S0;
      S1: if (x_in) 	  next_state = S3; else next_state = S0;
      S2:	if (~x_in) next_state = S0; else next_state = S2;
      S3: if (x_in)   next_state = S2; else next_state = S0;
    endcase 
  always @ (state, x_in) // Form the output
    case (state)
      S0:	y_out = 0;
      S1, S2, S3: y_out = ~x_in;
    endcase 
endmodule

